#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

// Linear Congruential Generator for random permutation
struct LCG {
    uint32_t seed;
    LCG(uint32_t s) : seed(s) {}
    uint32_t next() {
        seed = 1664525 * seed + 1013904223;
        return seed;
    }
};

// Host function to create random permutation
void create_random_permutation(uint32_t* array, size_t size, uint32_t seed) {
    // Initialize with sequential indices
    for (size_t i = 0; i < size; i++) {
        array[i] = static_cast<uint32_t>(i);
    }

    // Fisher-Yates shuffle with LCG
    LCG lcg(seed);
    for (size_t i = size - 1; i > 0; i--) {
        uint32_t j = lcg.next() % (i + 1);
        // Swap
        uint32_t temp = array[i];
        array[i] = array[j];
        array[j] = temp;
    }

    // Make it circular: each element points to the next in the permutation
    // The last element should point back to the first (index 0)
    array[size - 1] = 0;
}

__global__ void measure_dram_latency_kernel(volatile uint32_t* indices, uint64_t* cycles, size_t size, uint64_t iterations) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t idx = 0;

    // Compiler barrier before timing
    asm volatile("" : : : "memory");

    volatile uint64_t start = clock64();

    // Pointer-chasing loop with serial dependency
    #pragma unroll 1
    for (uint64_t i = 0; i < iterations; i++) {
        idx = indices[idx];
    }

    volatile uint64_t end = clock64();

    // Compiler barrier after timing
    asm volatile("" : : : "memory");

    // Anti-optimization: consume the result
    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    // Calculate average cycles per access
    *cycles = (end - start) / iterations;
}

int main() {
    const size_t WORKING_SET_SIZE = 32 * 1024 * 1024; // 32M elements = 128MB
    const uint64_t ITERATIONS = 10000000; // 10M iterations

    // Allocate host memory for permutation
    uint32_t* h_indices = (uint32_t*)malloc(WORKING_SET_SIZE * sizeof(uint32_t));
    if (!h_indices) {
        printf("Failed to allocate host memory\n");
        return 1;
    }

    // Allocate device memory
    uint32_t* d_indices;
    uint64_t* d_cycles;
    cudaMalloc(&d_indices, WORKING_SET_SIZE * sizeof(uint32_t));
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    // Array to store results from 3 trials
    uint64_t trial_results[3];

    // Run 3 trials with different random permutations
    for (int trial = 0; trial < 3; trial++) {
        // Create random permutation with different seed for each trial
        create_random_permutation(h_indices, WORKING_SET_SIZE, 12345 + trial);

        // Copy to device
        cudaMemcpy(d_indices, h_indices, WORKING_SET_SIZE * sizeof(uint32_t), cudaMemcpyHostToDevice);

        // Launch kernel
        measure_dram_latency_kernel<<<1, 1>>>(d_indices, d_cycles, WORKING_SET_SIZE, ITERATIONS);

        // Copy result back
        uint64_t h_cycles;
        cudaMemcpy(&h_cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
        cudaDeviceSynchronize();

        trial_results[trial] = h_cycles;
    }

    // Calculate median
    std::sort(trial_results, trial_results + 3);
    uint64_t median_cycles = trial_results[1];

    printf("dram_latency_cycles: %lu\n", (unsigned long)median_cycles);

    // Cleanup
    free(h_indices);
    cudaFree(d_indices);
    cudaFree(d_cycles);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

// Helper function to create a random permutation for pointer chasing
void create_random_permutation(uint32_t* array, size_t size) {
    // Initialize with sequential indices
    for (size_t i = 0; i < size; i++) {
        array[i] = static_cast<uint32_t>(i);
    }

    // Fisher-Yates shuffle with LCG
    uint64_t seed = 123456789;
    for (size_t i = size - 1; i > 0; i--) {
        seed = seed * 1664525 + 1013904223; // LCG
        size_t j = static_cast<size_t>(seed) % (i + 1);
        uint32_t temp = array[i];
        array[i] = array[j];
        array[j] = temp;
    }

    // Make it circular
    array[size - 1] = 0;
}

__global__ void measure_latency_kernel(volatile uint32_t* indices, uint64_t* cycles_out, size_t size, size_t iterations) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t idx = 0;
    asm volatile("" : : : "memory");

    volatile uint64_t start = clock64();
    #pragma unroll 1
    for (uint64_t i = 0; i < iterations; i++) {
        idx = indices[idx];
    }
    volatile uint64_t end = clock64();

    asm volatile("" : : : "memory");
    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    *cycles_out = (end - start) / iterations;
}

int main() {
    const size_t MB = 1024 * 1024;
    const size_t test_sizes[] = {
        1 * MB / sizeof(uint32_t),   // 1 MB
        2 * MB / sizeof(uint32_t),   // 2 MB
        4 * MB / sizeof(uint32_t),   // 4 MB
        8 * MB / sizeof(uint32_t),   // 8 MB
        16 * MB / sizeof(uint32_t),  // 16 MB
        32 * MB / sizeof(uint32_t),  // 32 MB
        64 * MB / sizeof(uint32_t),  // 64 MB
        128 * MB / sizeof(uint32_t)  // 128 MB
    };

    const int num_sizes = sizeof(test_sizes) / sizeof(test_sizes[0]);
    const size_t iterations = 2000000; // 2M iterations per measurement

    // Allocate device memory for results
    uint64_t* d_cycles;
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    uint64_t* h_cycles = new uint64_t;

    // Array to hold best latency for each size
    uint64_t best_latencies[num_sizes];
    memset(best_latencies, 0, sizeof(best_latencies));

    // Test each size 3 times and keep the best (lowest) latency
    for (int trial = 0; trial < 3; trial++) {
        for (int i = 0; i < num_sizes; i++) {
            size_t size = test_sizes[i];

            // Allocate and initialize indices array
            uint32_t* h_indices = new uint32_t[size];
            create_random_permutation(h_indices, size);

            uint32_t* d_indices;
            cudaMalloc(&d_indices, size * sizeof(uint32_t));
            cudaMemcpy(d_indices, h_indices, size * sizeof(uint32_t), cudaMemcpyHostToDevice);

            // Warmup
            measure_latency_kernel<<<1,1>>>(d_indices, d_cycles, size, 1000);
            cudaDeviceSynchronize();

            // Measure
            measure_latency_kernel<<<1,1>>>(d_indices, d_cycles, size, iterations);
            cudaDeviceSynchronize();

            cudaMemcpy(h_cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);

            if (best_latencies[i] == 0 || *h_cycles < best_latencies[i]) {
                best_latencies[i] = *h_cycles;
            }

            cudaFree(d_indices);
            delete[] h_indices;
        }
    }

    // Find the cliff: where latency increases by more than 50%
    float cache_size_mb = 0.0f;
    for (int i = 1; i < num_sizes; i++) {
        if (best_latencies[i-1] > 0) {
            float ratio = static_cast<float>(best_latencies[i]) / static_cast<float>(best_latencies[i-1]);
            if (ratio > 1.5f) { // 50% increase indicates cache miss
                cache_size_mb = static_cast<float>(test_sizes[i-1]) * sizeof(uint32_t) / MB;
                break;
            }
        }
    }

    // If no cliff found, use the smallest size that gave lowest latency
    if (cache_size_mb == 0.0f) {
        int min_idx = 0;
        for (int i = 1; i < num_sizes; i++) {
            if (best_latencies[i] < best_latencies[min_idx]) {
                min_idx = i;
            }
        }
        cache_size_mb = static_cast<float>(test_sizes[min_idx]) * sizeof(uint32_t) / MB;
    }

    printf("l2_cache_size_mb: %.1f\n", cache_size_mb);

    delete[] h_cycles;
    cudaFree(d_cycles);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void clock_measurement_kernel(uint64_t* cycles_out, float* time_out) {
    if (threadIdx.x == 0 && blockIdx.x == 0) {
        volatile uint64_t start_cycle = clock64();

        // Use a fixed number of iterations that should take >100ms
        const uint64_t iterations = 500000000ULL;
        volatile uint64_t counter = 0;

        asm volatile("" : : : "memory");

        for (uint64_t i = 0; i < iterations; i++) {
            counter += 1;  // Simple compute-bound operation
        }

        volatile uint64_t end_cycle = clock64();

        // Store results
        *cycles_out = end_cycle - start_cycle;
        *time_out = 0.0f; // Placeholder, will use events

        // Anti-optimization sink
        volatile uint64_t sink64 = (uint64_t)counter;
        asm volatile("" : "+l"(sink64) : : "memory");
    }
}

int main() {
    uint64_t* d_cycles;
    float* d_time;

    cudaMalloc(&d_cycles, sizeof(uint64_t));
    cudaMalloc(&d_time, sizeof(float));

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    // Warm up
    clock_measurement_kernel<<<1, 1>>>(d_cycles, d_time);
    cudaDeviceSynchronize();

    // Start timing
    cudaEventRecord(start);
    clock_measurement_kernel<<<1, 1>>>(d_cycles, d_time);
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float elapsed_ms = 0.0f;
    cudaEventElapsedTime(&elapsed_ms, start, stop);

    uint64_t cycles;
    cudaMemcpy(&cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);

    // Calculate frequency in MHz
    float elapsed_seconds = elapsed_ms / 1000.0f;
    float frequency_mhz = (cycles / elapsed_seconds) / 1000000.0f;

    printf("actual_boost_clock_mhz: %.0f\n", frequency_mhz);

    cudaFree(d_cycles);
    cudaFree(d_time);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

