#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void clock_measurement_kernel(uint64_t* cycle_count, uint64_t iterations) {
    if (threadIdx.x == 0 && blockIdx.x == 0) {
        volatile uint64_t start = clock64();
        volatile uint64_t counter = 0;
        #pragma unroll 1
        for (uint64_t i = 0; i < iterations; i++) {
            counter += i;
            counter *= 3;
        }
        volatile uint64_t end = clock64();
        *cycle_count = end - start;
        volatile uint64_t sink = counter;
        asm volatile("" : "+l"(sink) : : "memory");
    }
}

int main() {
    const int num_trials = 3;
    const uint64_t iterations = 1000000000ULL; // 1 billion
    float times[num_trials];
    float frequencies[num_trials];

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    uint64_t* d_cycles;
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    for (int trial = 0; trial < num_trials; trial++) {
        cudaEventRecord(start);
        clock_measurement_kernel<<<1, 1>>>(d_cycles, iterations);
        cudaEventRecord(stop);
        cudaEventSynchronize(stop);

        float elapsed_ms = 0.0f;
        cudaEventElapsedTime(&elapsed_ms, start, stop);

        double elapsed_seconds = elapsed_ms / 1000.0;
        double freq_mhz = iterations / elapsed_seconds / 1000000.0;

        times[trial] = elapsed_ms;
        frequencies[trial] = (float)freq_mhz;
    }

    std::sort(frequencies, frequencies + num_trials);
    float median_freq = frequencies[num_trials / 2];

    printf("actual_boost_clock_mhz: %.0f\n", median_freq);

    cudaFree(d_cycles);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}
